<script setup>
import { ref, reactive, onMounted, onUnmounted, computed } from 'vue'

// ===== 标题 =====
const titleChars = 'HAPPY BIRTHDAY!'.split('')
const titleColors = [
  '#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff',
  '#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff',
  '#ff9ff3', '#f368e0', '#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff',
]

// ===== 蜡烛 =====
const cakeBlown = ref(false)
const activeFlames = reactive([
  { x: 40, alive: true },
  { x: 68, alive: true },
  { x: 96, alive: true },
  { x: 124, alive: true },
  { x: 152, alive: true },
])

function blowCandle(idx) {
  activeFlames[idx].alive = false
  const allDead = activeFlames.every(f => !f.alive)
  if (allDead) {
    cakeBlown.value = true
  }
}

// ===== 气球 =====
const balloonColors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff9ff3', '#f368e0', '#00d2d3', '#ff9f43']
const balloons = reactive([])

function initBalloons() {
  balloons.length = 0
  for (let i = 0; i < 10; i++) {
    balloons.push({
      id: i,
      x: 5 + Math.random() * 85,
      delay: Math.random() * 3,
      speed: Math.random() * 3,
      color: balloonColors[i % balloonColors.length],
      popped: false,
    })
  }
}

function popBalloon(idx) {
  if (!balloons[idx].popped) {
    balloons[idx].popped = true
    setTimeout(() => {
      balloons[idx].x = -20 // float out
    }, 300)
  }
}

// ===== 彩带 =====
const confettiColors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff9ff3', '#f368e0', '#00d2d3', '#ff9f43']
const confetti = reactive([])

function initConfetti() {
  confetti.length = 0
  for (let i = 0; i < 40; i++) {
    confetti.push({
      x: Math.random() * 100,
      delay: Math.random() * 5,
      speed: Math.random() * 3,
      color: confettiColors[i % confettiColors.length],
      size: 4 + Math.random() * 8,
    })
  }
}

// ===== 星空粒子 =====
const starCanvas = ref(null)
let starAnimId = null

class Star {
  constructor(w, h) {
    this.reset(w, h)
  }
  reset(w, h) {
    this.x = Math.random() * w
    this.y = Math.random() * h
    this.size = 1 + Math.random() * 2
    this.speed = 0.2 + Math.random() * 0.5
    this.alpha = 0.3 + Math.random() * 0.7
    this.twinkleSpeed = 0.01 + Math.random() * 0.03
    this.twinklePhase = Math.random() * Math.PI * 2
  }
}

let stars = []
function initStars() {
  const canvas = starCanvas.value
  if (!canvas) return
  canvas.width = window.innerWidth
  canvas.height = window.innerHeight
  const count = Math.floor((canvas.width * canvas.height) / 3000)
  stars = Array.from({ length: count }, () => new Star(canvas.width, canvas.height))
}

function drawStars(time) {
  const canvas = starCanvas.value
  if (!canvas) return
  const ctx = canvas.getContext('2d')
  ctx.clearRect(0, 0, canvas.width, canvas.height)

  for (const star of stars) {
    const alpha = star.alpha * (0.5 + 0.5 * Math.sin(time * star.twinkleSpeed + star.twinklePhase))
    ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`
    ctx.fillRect(Math.floor(star.x), Math.floor(star.y), star.size, star.size)
  }

  starAnimId = requestAnimationFrame(drawStars)
}

// ===== 烟花 =====
const fireworks = reactive([])
let fireworkId = null

function triggerFireworks() {
  const canvas = starCanvas.value
  if (!canvas) return
  const cx = canvas.width / 2
  const cy = canvas.height / 3

  for (let burst = 0; burst < 3; burst++) {
    setTimeout(() => {
      const colors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff9ff3', '#f368e0']
      const color = colors[Math.floor(Math.random() * colors.length)]
      for (let i = 0; i < 24; i++) {
        const angle = (i / 24) * Math.PI * 2
        const speed = 40 + Math.random() * 60
        fireworks.push({
          x: cx + (burst - 1) * 100,
          y: cy + (burst - 1) * 50,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          color,
          life: 1,
          size: 3 + Math.random() * 3,
        })
      }
    }, burst * 400)
  }

  if (!fireworkId) {
    animateFireworks()
  }
}

function animateFireworks() {
  const canvas = starCanvas.value
  if (!canvas) return
  const ctx = canvas.getContext('2d')

  // 烟花绘制在单独的 overlay 上，但我们直接在 star canvas 上叠加绘制
  // 实际我们用一个独立的临时绘制方式

  for (let i = fireworks.length - 1; i >= 0; i--) {
    const f = fireworks[i]
    f.x += f.vx * 0.016
    f.y += f.vy * 0.016
    f.vy += 60 * 0.016 // gravity
    f.life -= 0.02
    f.size *= 0.995

    if (f.life <= 0 || f.size < 0.5) {
      fireworks.splice(i, 1)
    }
  }

  if (fireworks.length > 0) {
    fireworkId = requestAnimationFrame(animateFireworks)
  } else {
    fireworkId = null
  }
}

// ===== 音乐控制 (8-bit 风格) =====
const musicOn = ref(false)
let audioCtx = null
let musicInterval = null

function playBeep(freq, duration) {
  try {
    if (!audioCtx) {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)()
    }
    const osc = audioCtx.createOscillator()
    const gain = audioCtx.createGain()
    osc.connect(gain)
    gain.connect(audioCtx.destination)
    osc.type = 'square'
    osc.frequency.value = freq
    gain.gain.setValueAtTime(0.08, audioCtx.currentTime)
    gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration)
    osc.start()
    osc.stop(audioCtx.currentTime + duration)
  } catch (e) { /* no audio */ }
}

function toggleMusic() {
  musicOn.value = !musicOn.value
  if (musicOn.value) {
    // 播放简单的8-bit生日快乐旋律
    const melody = [
      // Happy Birthday 简谱
      [262, 0.2], [262, 0.2], [294, 0.4], [262, 0.4],
      [349, 0.4], [330, 0.8],
      [262, 0.2], [262, 0.2], [294, 0.4], [262, 0.4],
      [392, 0.4], [349, 0.8],
      [262, 0.2], [262, 0.2], [523, 0.4], [440, 0.4],
      [349, 0.4], [330, 0.4], [294, 0.4],
      [494, 0.2], [494, 0.2], [440, 0.4], [349, 0.4],
      [392, 0.4], [349, 0.8],
    ]
    let idx = 0
    musicInterval = setInterval(() => {
      if (idx >= melody.length) idx = 0
      const [freq, dur] = melody[idx]
      playBeep(freq, dur)
      idx++
    }, 500)
  } else {
    if (musicInterval) {
      clearInterval(musicInterval)
      musicInterval = null
    }
  }
}

// ===== 重置 =====
function restartPage() {
  cakeBlown.value = false
  activeFlames.forEach(f => f.alive = true)
  initBalloons()
  initConfetti()
}

// ===== 键盘控制 =====
function onKeyDown(e) {
  if (e.key === 'r' || e.key === 'R') restartPage()
  if (e.key === 'f' || e.key === 'F') triggerFireworks()
  if (e.key === 'm' || e.key === 'M') toggleMusic()
}

// ===== 窗口自适应 =====
function onResize() {
  initStars()
}

// ===== 生命周期 =====
onMounted(() => {
  initStars()
  initBalloons()
  initConfetti()
  drawStars(0)
  window.addEventListener('resize', onResize)
})

onUnmounted(() => {
  if (starAnimId) cancelAnimationFrame(starAnimId)
  if (fireworkId) cancelAnimationFrame(fireworkId)
  if (musicInterval) clearInterval(musicInterval)
  if (audioCtx) audioCtx.close()
  window.removeEventListener('resize', onResize)
})
</script>

