// ===== 星空粒子 =====
const starCanvas = ref(null)
let starAnimId = null

class Star {
  constructor(w, h) {
    this.reset(w, h)
  }
  reset(w, h) {
    this.x = Math.random() * w
    this.y = Math.random() * h
    this.size = 1 + Math.random() * 2
    this.speed = 0.2 + Math.random() * 0.5
    this.alpha = 0.3 + Math.random() * 0.7
    this.twinkleSpeed = 0.01 + Math.random() * 0.03
    this.twinklePhase = Math.random() * Math.PI * 2
  }
}

let stars = []
function initStars() {
  const canvas = starCanvas.value
  if (!canvas) return
  canvas.width = window.innerWidth
  canvas.height = window.innerHeight
  const count = Math.floor((canvas.width * canvas.height) / 3000)
  stars = Array.from({ length: count }, () => new Star(canvas.width, canvas.height))
}

function drawStars(time) {
  const canvas = starCanvas.value
  if (!canvas) return
  const ctx = canvas.getContext('2d')
  ctx.clearRect(0, 0, canvas.width, canvas.height)

  for (const star of stars) {
    const alpha = star.alpha * (0.5 + 0.5 * Math.sin(time * star.twinkleSpeed + star.twinklePhase))
    ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`
    ctx.fillRect(Math.floor(star.x), Math.floor(star.y), star.size, star.size)
  }

  starAnimId = requestAnimationFrame(drawStars)
}

// ===== 烟花 =====
const fireworks = reactive([])
let fireworkId = null

function triggerFireworks() {
  const canvas = starCanvas.value
  if (!canvas) return
  const cx = canvas.width / 2
  const cy = canvas.height / 3

  for (let burst = 0; burst < 3; burst++) {
    setTimeout(() => {
      const colors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff9ff3', '#f368e0']
      const color = colors[Math.floor(Math.random() * colors.length)]
      for (let i = 0; i < 24; i++) {
        const angle = (i / 24) * Math.PI * 2
        const speed = 40 + Math.random() * 60
        fireworks.push({
          x: cx + (burst - 1) * 100,
          y: cy + (burst - 1) * 50,
          vx: Math.cos(angle) * speed,
          vy: Math.sin(angle) * speed,
          color,
          life: 1,
          size: 3 + Math.random() * 3,
        })
      }
    }, burst * 400)
  }

  if (!fireworkId) {
    animateFireworks()
  }
}

function animateFireworks() {
  const canvas = starCanvas.value
  if (!canvas) return
  const ctx = canvas.getContext('2d')

  for (let i = fireworks.length - 1; i >= 0; i--) {
